  const getRawText = () => {
    const lines = [`${'='.repeat(50)}\n신입 면접 · 작성한 답변 모음\n${'='.repeat(50)}\n`];
    lines.push(`지원 회사: ${basicInfo.company || '-'}`);
    lines.push(`지원 직무: ${basicInfo.position || '-'}`);
    lines.push(`산업: ${basicInfo.industry || '-'}\n`);
    QUESTIONS.forEach(qq => {
      const core = answers[`${qq.label}_core`]?.trim();
      const finalA = answers[`${qq.label}_final`]?.trim();
      if (core || finalA) {
        lines.push(`\n━━━ ${qq.label}. ${qq.title}${qq.required ? ' [필수]' : ''} ━━━`);
        if (core) lines.push(`\n[핵심 문장]\n${core}`);
        // Step 2 세부 질문 답변
        qq.stages.forEach((st, si) => {
          st.questions.forEach((sq, qi) => {
            const a = answers[`${qq.label}_s${si}_q${qi}`]?.trim();
            if (a) lines.push(`  · ${sq} → ${a}`);
          });
        });
        if (finalA) lines.push(`\n[최종 답변]\n${finalA}`);
        // Step 4 꼬리질문
        qq.tails.forEach((t, ti) => {
          const ta = answers[`${qq.label}_tail_${ti}`]?.trim();
          if (ta) lines.push(`\n[꼬리질문: "${t.q}"]\n${ta}`);
        });
      }
    });
    return lines.join('\n');
  };

